#!/usr/bin/env node
/**
 * ora-calendar-analytics.js
 * Requirements 27, 36, 37, 38, 39: Calendar intelligence and weekly reporting.
 *
 * Deterministic math. Zero LLM (narrative generated by llm-task in pipeline).
 */

function analyzeWeek(events, priorWeeks, rules) {
  const meetings = events.filter(e => !e.is_focus_block && !e.is_all_day);
  const focusBlocks = events.filter(e => e.is_focus_block);

  // --- Total meeting hours ---
  const meetingMinutes = meetings.reduce((sum, m) => {
    return sum + (new Date(m.end) - new Date(m.start)) / (1000 * 60);
  }, 0);
  const meetingHours = Math.round(meetingMinutes / 60 * 10) / 10;

  // --- Focus time ---
  const focusMinutes = focusBlocks.reduce((sum, b) => {
    return sum + (new Date(b.end) - new Date(b.start)) / (1000 * 60);
  }, 0);
  const focusHours = Math.round(focusMinutes / 60 * 10) / 10;

  const earliestHour = parseTimeToHour(rules?.earliest_start || '09:00');
  const latestHour = parseTimeToHour(rules?.latest_end || '18:00');
  const availableHoursPerDay = latestHour - earliestHour;
  const workDays = (rules?.staffed_days || [1, 2, 3, 4, 5]).length;
  const totalAvailableHours = availableHoursPerDay * workDays;
  const focusPct = totalAvailableHours > 0 ? Math.round((focusHours / totalAvailableHours) * 100) : 0;
  const meetingPct = totalAvailableHours > 0 ? Math.round((meetingHours / totalAvailableHours) * 100) : 0;

  // --- Meeting load score (Req 39) ---
  const loadScore = totalAvailableHours > 0 ? Math.min(100, Math.round((meetingHours / totalAvailableHours) * 100)) : 0;

  // --- Per-day breakdown ---
  const byDay = {};
  for (const m of meetings) {
    const day = new Date(m.start).toLocaleDateString('en-US', { weekday: 'long' });
    if (!byDay[day]) byDay[day] = { count: 0, hours: 0 };
    byDay[day].count++;
    byDay[day].hours += (new Date(m.end) - new Date(m.start)) / (1000 * 60 * 60);
  }
  for (const d of Object.keys(byDay)) {
    byDay[d].hours = Math.round(byDay[d].hours * 10) / 10;
  }

  const heaviestDay = Object.entries(byDay).sort((a, b) => b[1].hours - a[1].hours)[0];
  const lightestDay = Object.entries(byDay).sort((a, b) => a[1].hours - b[1].hours)[0];

  // --- Meeting type distribution (Req 38) ---
  const byType = {};
  for (const m of meetings) {
    const type = m.meeting_type || m.category || 'uncategorized';
    if (!byType[type]) byType[type] = { count: 0, hours: 0 };
    byType[type].count++;
    byType[type].hours += (new Date(m.end) - new Date(m.start)) / (1000 * 60 * 60);
  }
  for (const t of Object.keys(byType)) {
    byType[t].hours = Math.round(byType[t].hours * 10) / 10;
    byType[t].pct = Math.round((byType[t].hours / meetingHours) * 100) || 0;
  }

  // --- Recurring meetings running over (Req 27) ---
  const recurringOverruns = detectOverruns(events);

  // --- Pattern detection (Req 37) ---
  const patterns = detectPatterns(byDay, priorWeeks, loadScore, focusPct);

  // --- Prior week comparison ---
  const priorWeek = priorWeeks?.[0];
  const priorMeetingHours = priorWeek?.meeting_hours || null;
  const priorLoadScore = priorWeek?.load_score || null;

  return {
    meeting_hours: meetingHours,
    focus_hours: focusHours,
    focus_pct: focusPct,
    meeting_pct: meetingPct,
    load_score: loadScore,
    total_meetings: meetings.length,
    by_day: byDay,
    heaviest_day: heaviestDay ? { day: heaviestDay[0], hours: heaviestDay[1].hours } : null,
    lightest_day: lightestDay ? { day: lightestDay[0], hours: lightestDay[1].hours } : null,
    by_type: byType,
    recurring_overruns: recurringOverruns,
    patterns,
    comparison: {
      prior_meeting_hours: priorMeetingHours,
      meeting_hours_change: priorMeetingHours ? meetingHours - priorMeetingHours : null,
      prior_load_score: priorLoadScore,
      load_score_change: priorLoadScore ? loadScore - priorLoadScore : null
    },
    timestamp: new Date().toISOString()
  };
}

function detectOverruns(events) {
  // Group recurring meetings by series identifier or title
  const recurring = {};
  for (const e of events) {
    if (!e.recurring_id && !e.series_title) continue;
    const key = e.recurring_id || e.series_title || e.title;
    if (!recurring[key]) recurring[key] = [];
    recurring[key].push(e);
  }

  const overruns = [];
  for (const [key, instances] of Object.entries(recurring)) {
    if (instances.length < 3) continue;
    const scheduledMinutes = (new Date(instances[0].end) - new Date(instances[0].start)) / (1000 * 60);
    // Check if consistently running over by looking at the next event's start
    // (proxy for actual end time — if next meeting starts late, this one ran over)
    let overrunCount = 0;
    for (const inst of instances) {
      if (inst.actual_duration_minutes && inst.actual_duration_minutes > scheduledMinutes + 5) {
        overrunCount++;
      }
    }
    if (overrunCount >= 3) {
      overruns.push({
        meeting: key,
        scheduled_minutes: scheduledMinutes,
        avg_actual_minutes: Math.round(instances.reduce((s, i) => s + (i.actual_duration_minutes || scheduledMinutes), 0) / instances.length),
        overrun_count: overrunCount,
        total_instances: instances.length
      });
    }
  }

  return overruns;
}

function detectPatterns(currentByDay, priorWeeks, currentLoadScore, currentFocusPct) {
  const patterns = [];
  if (!priorWeeks || priorWeeks.length < 3) return patterns;

  // Heaviest day consistency
  const dayLoads = {};
  for (const week of [...priorWeeks.slice(0, 3)]) {
    if (!week.by_day) continue;
    for (const [day, data] of Object.entries(week.by_day)) {
      if (!dayLoads[day]) dayLoads[day] = [];
      dayLoads[day].push(data.hours);
    }
  }
  for (const [day, hours] of Object.entries(dayLoads)) {
    const currentDayHours = currentByDay[day]?.hours || 0;
    if (hours.length >= 3 && hours.every(h => h >= 5) && currentDayHours >= 5) {
      patterns.push({
        type: 'consistently_heavy_day',
        day,
        weeks: hours.length + 1,
        avg_hours: Math.round((hours.reduce((a, b) => a + b, 0) + currentDayHours) / (hours.length + 1) * 10) / 10,
        suggestion: `${day}s have been your heaviest day for ${hours.length + 1} consecutive weeks. Want me to protect ${day} afternoons?`
      });
    }
  }

  // Load score trend
  const priorScores = priorWeeks.slice(0, 4).map(w => w.load_score).filter(s => s !== undefined);
  if (priorScores.length >= 3) {
    const increasing = priorScores.every((s, i) => i === 0 || s <= priorScores[i - 1]) && currentLoadScore > priorScores[0];
    if (increasing) {
      patterns.push({
        type: 'increasing_load',
        weeks: priorScores.length + 1,
        trend: [...priorScores.reverse(), currentLoadScore],
        suggestion: `Your meeting load has been growing for ${priorScores.length + 1} weeks (${priorScores[0]} → ${currentLoadScore}). Your focus time is being compressed.`
      });
    }
  }

  return patterns;
}

function parseTimeToHour(timeStr) {
  const [h, m] = (timeStr || '09:00').split(':').map(Number);
  return h + (m || 0) / 60;
}

async function main() {
  const input = await readStdin();
  if (!input) {
    process.stderr.write('No input provided');
    process.exit(1);
  }

  const result = analyzeWeek(
    input.events || [],
    input.prior_weeks || [],
    input.rules || {}
  );

  process.stdout.write(JSON.stringify(result));
}

function readStdin() {
  return new Promise((resolve) => {
    let data = '';
    process.stdin.setEncoding('utf8');
    process.stdin.on('data', chunk => data += chunk);
    process.stdin.on('end', () => {
      try { resolve(JSON.parse(data)); }
      catch { resolve(null); }
    });
    if (process.stdin.isTTY) resolve(null);
  });
}

module.exports = { analyzeWeek };

if (require.main === module) {
  main().catch(err => {
    process.stderr.write(err.message);
    process.exit(1);
  });
}
